async function loadUser(id) {
  try {
    const res  = await fetch(`/api/users/${id}`);
    if (!res.ok) throw new Error('用户不存在');
    return await res.json();
  } catch (err) {
    console.error('加载失败:', err.message);
    return null;  // 兜底返回
  }
}

async function loadList() {
  // 失败时返回空数组，不抛错
  const data = await fetch('/api/list')
    .then(r => r.json())
    .catch(() => []);
  return data;
}

